        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult VisualizarPrevia(PacienteRespostaViewModel vm)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            Int32 idAss = (Int32)Session["IdAssinante"];
            List<SelectListItem> ver = new List<SelectListItem>();
            ver.Add(new SelectListItem() { Text = "Sim", Value = "1" });
            ver.Add(new SelectListItem() { Text = "Não", Value = "0" });
            ViewBag.Ver = new SelectList(ver, "Value", "Text");
            if (ModelState.IsValid)
            {
                try
                {
                    // Sanitização

                    // Critica
                    if (vm.RECO_IN_ANAMNESE == null)
                    {
                        vm.RECO_IN_ANAMNESE = 0;
                    }
                    if (vm.RECO_IN_VISTO == null)
                    {
                        vm.RECO_IN_VISTO = 0;
                    }

                    // Executa a operação
                    Int32? anamnese = vm.RECO_IN_ANAMNESE;
                    USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
                    RESPOSTA_CONSULTA item = Mapper.Map<PacienteRespostaViewModel, RESPOSTA_CONSULTA>(vm);
                    PACIENTE pac = baseApp.GetItemById(item.PACI_CD_ID.Value);
                    Int32 volta = baseApp.ValidateEditResposta(item);

                    // Atualiza Anamnese
                    if (item.RECO_IN_ANAMNESE == 0)
                    {
                        Session["Pacientes"] = null;
                        String dataHoje = DateTime.Today.Date.ToLongDateString();
                        PACIENTE_ANAMNESE ana = pac.PACIENTE_ANAMNESE.Where(p => p.PAAM_IN_ATIVO == 1).FirstOrDefault();
                        PACIENTE_ANAMNESE anam = RemontarAnamnese(ana);
                        if (item.RECO_TX_MOTIVO != null)
                        {
                            String velho = anam.PAAM_TX_TEXTO_LIVRE;
                            String novo = "=== Informação Prévia de Consulta === " + Environment.NewLine + item.RECO_TX_MOTIVO;
                            if (velho == null & novo != String.Empty)
                            {
                                anam.PAAM_TX_TEXTO_LIVRE = dataHoje + "\r\n" + novo;
                            }
                            if (velho != null & novo != String.Empty)
                            {
                                String tripa = velho.Substring(velho.Length - 4, 4);
                                if (tripa == "\r\n")
                                {
                                    velho = velho.Substring(0, velho.Length - 4);
                                }
                                anam.PAAM_TX_TEXTO_LIVRE = velho + "\r\n\r\n" + dataHoje + "\r\n" + novo;
                            }
                        }
                        Int32 voltaAna = baseApp.ValidateEditAnamnesePrevia(anam);

                        RESPOSTA_CONSULTA resp = baseApp.GetRespostaById(item.RECO_CD_ID);
                        resp.RECO_IN_ANAMNESE = 1;
                        Int32 volta2 = baseApp.ValidateEditResposta(resp);
                    }

                    // Configura serilização
                    JsonSerializerSettings settings = new JsonSerializerSettings
                    {
                        ReferenceLoopHandling = ReferenceLoopHandling.Ignore,
                        NullValueHandling = NullValueHandling.Ignore
                    };

                    // Monta Log
                    DTO_Paciente_Resposta dto = MontarPacienteRespostaDTOObj(item);
                    String json = JsonConvert.SerializeObject(dto, settings);
                    LOG log = new LOG
                    {
                        LOG_DT_DATA = DateTime.Now,
                        ASSI_CD_ID = usuarioLogado.ASSI_CD_ID,
                        USUA_CD_ID = usuarioLogado.USUA_CD_ID,
                        LOG_NM_OPERACAO = "Paciente - Resposta - Visualização",
                        LOG_IN_ATIVO = 1,
                        LOG_TX_REGISTRO = json,
                        LOG_IN_SISTEMA = 6
                    };
                    Int32 volta1 = logApp.ValidateCreate(log);

                    // Verifica retorno
                    Session["PacienteAlterada"] = 1;
                    Session["NivelPaciente"] = 3;

                    // Grava historico
                    PACIENTE_HISTORICO hist = new PACIENTE_HISTORICO();
                    hist.ASSI_CD_ID = usuarioLogado.ASSI_CD_ID;
                    hist.USUA_CD_ID = usuarioLogado.USUA_CD_ID;
                    hist.PACI_CD_ID = pac.PACI__CD_ID;
                    hist.PAHI_DT_DATA = DateTime.Now;
                    hist.PAHI_IN_TIPO = 2;
                    hist.PAHI_IN_CHAVE = item.RECO_CD_ID;
                    hist.PAHI_NM_OPERACAO = "Paciente - Visualização de Resposta";
                    hist.PAHI_DS_DESCRICAO = "Paciente: " + pac.PACI_NM_NOME.ToUpper() + " - Resposta visualizada: " + item.RECO_DT_DATA.Value.ToShortDateString();
                    Int32 voltaHist = baseApp.ValidateCreateHistorico(hist);

                    // Mensagem do CRUD
                    Session["MsgCRUD"] = "A informação prévia gerada em " + item.RECO_DT_DATA.Value.ToShortDateString() + " do paciente " + pac.PACI_NM_NOME.ToUpper() + " foi visualizada com sucesso";
                    Session["MensPaciente"] = 61;

                    return RedirectToAction("VoltarAnexoPaciente");
                }
                catch (Exception ex)
                {
                    ViewBag.Message = ex.Message;
                    Session["TipoVolta"] = 2;
                    Session["VoltaExcecao"] = "Paciente";
                    Session["Excecao"] = ex;
                    Session["ExcecaoTipo"] = ex.GetType().ToString();
                    GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                    Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                    return RedirectToAction("TrataExcecao", "BaseAdmin");
                }
            }
            else
            {
                return View(vm);
            }
        }

        [HttpGet]
        public ActionResult MontarTelaEncerrarConsultaMaterial()
        {
            try
            {
                // Verifica se tem usuario logado
                USUARIO usuario = new USUARIO();
                if ((String)Session["Ativa"] == null)
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                if ((USUARIO)Session["UserCredentials"] != null)
                {
                    usuario = (USUARIO)Session["UserCredentials"];

                    // Verfifica permissão
                    if (usuario.PERFIL.PERF_IN_PACIENTE_CONSULTA_ACESSO == 0)
                    {
                        Session["MensPermissao"] = 2;
                        Session["ModuloPermissao"] = "Paciente";
                        return RedirectToAction("MontarTelaPaciente", "Paciente");
                    }
                }
                else
                {
                    return RedirectToAction("Logout", "ControleAcesso");
                }
                Int32 idAss = (Int32)Session["IdAssinante"];
                Session["ModuloAtual"] = "Consultas - Encerramento";

                // Mensagem
                if (Session["MensPaciente"] != null)
                {
                    if ((Int32)Session["MensPaciente"] == 1)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0016", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 62)
                    {
                        ModelState.AddModelError("", CRMSys_Base.ResourceManager.GetString("M0586", CultureInfo.CurrentCulture));
                    }
                    if ((Int32)Session["MensPaciente"] == 63)
                    {
                        TempData["MensagemAcerto"] = (String)Session["MsgCRUD"];
                        TempData["TemMensagem"] = 1;
                    }
                }

                // Recupera informações
                CONFIGURACAO conf = CarregaConfiguracaoGeral();
                PACIENTE_CONSULTA cons = (PACIENTE_CONSULTA)Session["ConsultaEncerra"];
                VALOR_CONSULTA tipo = vcApp.GetItemById(cons.VACO_CD_ID.Value);
                PACIENTE pac = baseApp.GetItemById(cons.PACI_CD_ID);
                ViewBag.Perfil = usuario.PERFIL.PERF_SG_SIGLA;

                // Acerta estado    
                Session["MensPaciente"] = null;

                // Carrega view
                ValorConsulta1ViewModel vm = Mapper.Map<VALOR_CONSULTA, ValorConsulta1ViewModel>(tipo);
                vm.PACI_NM_NOME = pac.PACI_NM_NOME;
                vm.PACI_NR_CPF = pac.PACI_NR_CPF;
                vm.PACI_NR_CELULAR = pac.PACI_NR_CELULAR;
                vm.PACI_NR_TELEFONE = pac.PACI_NR_TELEFONE;
                vm.PACI_DT_NASCIMENTO = pac.PACI_DT_NASCIMENTO;
                vm.PACO_DT_CONSULTA = cons.PACO_DT_CONSULTA;
                vm.PACO_HR_INICIO = cons.PACO_HR_INICIO;
                vm.PACO_HR_FINAL = cons.PACO_HR_FINAL;

                // Grava Acesso
                ControleAcessoMetodo grava = new ControleAcessoMetodo(aceApp);
                Int32 voltaX = grava.GravaAcesso(usuario.USUA_CD_ID, usuario.ASSI_CD_ID, "PACIENTE_CONSULTA_ENCERRAR", "Paciente2", "MontarTelaEncerrarConsultaMaterial");
                return View(vm);
            }
            catch (Exception ex)
            {
                ViewBag.Message = ex.Message;
                Session["TipoVolta"] = 2;
                Session["VoltaExcecao"] = "Paciente";
                Session["Excecao"] = ex;
                Session["ExcecaoTipo"] = ex.GetType().ToString();
                GravaLogExcecao grava = new GravaLogExcecao(usuApp);
                Int32 voltaX = grava.GravarLogExcecao(ex, "Paciente", "WebDoctor", 1, (USUARIO)Session["UserCredentials"]);
                return RedirectToAction("TrataExcecao", "BaseAdmin");
            }
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        [ValidateInput(false)]
        public ActionResult MontarTelaEncerrarConsultaMaterial(ValorConsulta1ViewModel vm1)
        {
            if ((String)Session["Ativa"] == null)
            {
                return RedirectToAction("Logout", "ControleAcesso");
            }
            USUARIO usuarioLogado = (USUARIO)Session["UserCredentials"];
            Int32 idAss = (Int32)Session["IdAssinante"];
            if (ModelState.IsValid)
            {
                try
                {
                    // Recupera informações
                    List<VALOR_CONSULTA_MATERIAL> mats = vm1.VALOR_CONSULTA_MATERIAL.ToList();

                    // Configura serialização
                    JsonSerializerSettings settings = new JsonSerializerSettings
                    {
                        ReferenceLoopHandling = ReferenceLoopHandling.Ignore,
                        NullValueHandling = NullValueHandling.Ignore
                    };

                    // Processa materiais
                    Int32 excede = 0;
                    foreach (VALOR_CONSULTA_MATERIAL mat in mats)
                    {
                        // Recupera produto
                        PRODUTO prod = prodApp.GetItemById(mat.PROD_CD_ID);
                        Session["ProdAntes"] = prod;

                        // Critica quantidade
                        if (mat.VCMA_QN_QUANTIDADE_REAL <= 0)
                        {
                            mat.VCMA_QN_QUANTIDADE_REAL = 0;
                        }
                        if (mat.VCMA_QN_QUANTIDADE_REAL == null)
                        {
                            mat.VCMA_QN_QUANTIDADE_REAL = 0;
                        }
                        if (mat.VCMA_QN_QUANTIDADE > prod.PROD_VL_ESTOQUE_ATUAL)
                        {
                            excede = 1;
                        }

                        // Monta e grava movimentação de entrada 
                        if (mat.VCMA_QN_QUANTIDADE_REAL > 0)
