                            novo.PROD_IN_ATIVO = prod.PROD_IN_ATIVO;
                            novo.PROD_IN_COMPOSTO = prod.PROD_IN_COMPOSTO;
                            novo.PROD_IN_FRACIONADO = prod.PROD_IN_FRACIONADO;
