                            String json2 = JsonConvert.SerializeObject(dto2, settings);
                            DTO_Produto dto2Antes = MontarProdutoDTOObj((PRODUTO)Session["ProdAntes"]);
                            String json2Antes = JsonConvert.SerializeObject(dto2Antes, settings);
                            LOG log2 = new LOG
                            {
